<style>
    :root{--ink:#26312a;--muted:#667085;--green:#7bc98c;--green-dark:#37844d;--soft:#f5f7f4;--line:#e2e8e2;--card:#fff;--max:1120px}*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;font-family:"Plus Jakarta Sans",ui-sans-serif,system-ui,-apple-system,sans-serif;color:var(--ink);background:#fff}a{color:inherit}.wrap{width:min(var(--max),calc(100% - 40px));margin:auto}.nav{min-height:76px;display:flex;align-items:center;gap:26px}.brand{display:flex;align-items:center;gap:10px;text-decoration:none;font-size:21px;font-weight:850}.brand img{width:36px;height:36px;border-radius:11px}.navlinks{margin-left:auto;display:flex;align-items:center;gap:24px}.navlinks a{text-decoration:none;color:var(--muted);font-size:14px;font-weight:650}.nav-login,.button{display:inline-flex;align-items:center;justify-content:center;min-height:46px;padding:0 24px;border:1px solid var(--line);border-radius:999px;background:#fff;color:var(--ink)!important;text-decoration:none!important;font-weight:750!important}.button{border-color:transparent;background:var(--green);color:#173a28!important;cursor:pointer}.button.outline{border-color:var(--line);background:#fff}.public-beta-banner{background:#e9f8ed;color:#285d37;text-align:center;font-size:13px;font-weight:650}.public-beta-banner-inner{padding:9px}.hero{padding:92px 0 72px;text-align:center}.hero h1{max-width:900px;margin:0 auto;font-size:clamp(42px,7vw,72px);line-height:1;letter-spacing:-.045em}.hero-subhead{max-width:720px;margin:24px auto 0;color:var(--muted);font-size:clamp(18px,2.3vw,24px);line-height:1.55}.hero-actions{display:flex;justify-content:center;gap:12px;flex-wrap:wrap;margin-top:32px}.proof{margin-top:32px;color:var(--muted);font-weight:650}.section{padding:86px 0}.section.soft,.pricing-panel{background:var(--soft)}.section-head{max-width:760px;margin:0 auto 46px;text-align:center}.section-kicker{color:var(--green-dark);font-size:13px;font-weight:800;letter-spacing:.08em}.section-head h2{margin:10px 0 0;font-size:clamp(34px,5vw,52px);letter-spacing:-.035em}.section-head p{color:var(--muted);font-size:18px;line-height:1.6}.feature-grid,.plans{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:22px}.feature-card,.plan,.review-card{border:1px solid var(--line);border-radius:22px;background:var(--card);padding:26px;box-shadow:0 14px 45px rgba(27,55,35,.06)}.feature-card img{width:100%;aspect-ratio:9/16;object-fit:cover;object-position:top;border-radius:14px;border:1px solid var(--line);margin-bottom:20px}.feature-card h3,.plan h3{margin:0 0 10px;font-size:23px}.feature-card p,.for,.review-card p{color:var(--muted);line-height:1.65}.reviews-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.review-user{display:flex;align-items:center;gap:12px;margin-bottom:15px}.review-user img{width:44px;height:44px;border-radius:50%}.review-user h3{margin:0;font-size:15px}.review-user span{color:var(--muted);font-size:13px}.cta-band{padding:80px 0;text-align:center}.cta-band h2{font-size:clamp(34px,5vw,52px);margin:0}.signup-form{display:flex;justify-content:center;gap:10px;flex-wrap:wrap;margin-top:24px}.signup-form input{min-width:min(340px,100%);min-height:48px;border:1px solid var(--line);border-radius:999px;padding:0 20px;font:inherit}.footer{display:flex;justify-content:space-between;gap:20px;flex-wrap:wrap;padding:34px 0;border-top:1px solid var(--line);color:var(--muted);font-size:14px}.pricing-hero{padding-bottom:54px}.pricing-panel{padding:76px 0 96px}.billing-switch{display:flex;justify-content:center;margin:0 0 42px}.segmented{display:flex;border:1px solid var(--line);border-radius:999px;background:#fff;padding:4px}.segmented button{border:0;border-radius:999px;background:transparent;padding:10px 18px;font:inherit;font-weight:700;cursor:pointer}.segmented button.active{background:var(--green)}.plans{align-items:stretch}.plan{display:flex;flex-direction:column;min-height:610px}.plan.popular{border:2px solid var(--green)}.badge{border-radius:999px;background:var(--green);padding:4px 8px;font-size:11px}.price{display:flex;align-items:end;gap:4px;margin:18px 0 24px}.amount{font-size:48px;font-weight:850;letter-spacing:-.04em}.period{color:var(--muted)}.features{padding:0;list-style:none;display:grid;gap:13px}.features li{padding-left:24px;position:relative;line-height:1.45}.features li:before{content:"✓";position:absolute;left:0;color:var(--green-dark);font-weight:900}.plan .button{margin-top:auto}.fine{text-align:center;color:var(--muted);font-size:12px;margin-top:10px}.signup-modal{position:fixed;inset:0;display:grid;place-items:center;background:rgba(20,30,23,.4);padding:20px}.signup-modal-card{max-width:440px;border-radius:22px;background:#fff;padding:28px;text-align:center}.mobile-menu{display:none}@media(max-width:820px){.navlinks{display:none}.feature-grid,.reviews-grid,.plans{grid-template-columns:1fr}.hero{padding-top:64px}.plan{min-height:0}.mobile-menu{display:block;margin-left:auto}.mobile-menu summary{cursor:pointer}.mobile-menu-panel{position:absolute;right:20px;display:grid;gap:10px;border:1px solid var(--line);border-radius:16px;background:#fff;padding:14px;box-shadow:0 20px 50px rgba(0,0,0,.12)}.mobile-menu-panel a{text-decoration:none;padding:6px}}
</style>
